17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const INSURANCE_VALUES: Record<string, number> = {
27	  sword: 1000,
28	  amulet: 600,
29	  staff: 800,
30	  potion: 400,
31	  rune: 250,
32	  moonstone: 250,
33	};
