35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	const DEDUCTIBLE = 100;
37	const PROCESSING_FEE = 5;
38	const BLOCK_SIZE = 3;
39	const BLOCK_PRICE = 60;
40	const CURSED_SURCHARGE_RATE = 0.5;
41	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
42	const HIGH_ENCHANTMENT_THRESHOLD = 5;
43	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
44	const LOYALTY_DISCOUNT_RATE = 0.2;
45	const LOYALTY_YEARS_THRESHOLD = 2;
46	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
47	
48	const calculateQuotePremium = (items: Item[], customer: { yearsWithMHPCO: number }, quoteIndex: number): number => {
49	  let basePremium = 0;
50	  let itemSurcharges = 0;
51	  const componentCounts: Record<string, number> = {};
52	
53	  for (const item of items) {
54	    if (COMPONENT_TYPES.has(item.type)) {
55	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
56	    } else {
57	      const itemBasePremium = BASE_PREMIUMS[item.type];
58	      basePremium += itemBasePremium;
59	      if (item.cursed) {
60	        itemSurcharges += itemBasePremium * CURSED_SURCHARGE_RATE;
61	      }
62	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
63	        itemSurcharges += itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
64	      }
65	    }
66	  }
67	
68	  for (const [type, count] of Object.entries(componentCounts)) {
69	    basePremium += count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUMS[type];
70	  }
71	
72	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
73	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
74	  const followUpDiscount = quoteIndex > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
75	  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
76	};
