79	  let quoteCount = 0;
80	  const policies: { items: Item[]; insuranceSum: number; remainingCap: number }[] = [];
81	  const results = scenario.steps.map((step, index) => {
82	    if (step.op === "quote") {
83	      const premium = calculateQuotePremium(step.items, scenario.customer, quoteCount);
84	      const insuranceSum = step.items.reduce(
85	        (sum: number, item: Item) => sum + INSURANCE_VALUES[item.type],
86	        0,
87	      );
88	      policies[index] = { items: step.items, insuranceSum, remainingCap: insuranceSum * 2 };
89	      quoteCount++;
90	      return { premium };
91	    } else {
92	      const policy = policies[step.policy];
93	      let totalPayout = 0;
94	      for (const damage of step.incident.damages) {
95	        const payout = damage.amount - DEDUCTIBLE;
96	        totalPayout += Math.max(0, payout);
97	      }
98	      totalPayout = Math.min(totalPayout, policy.remainingCap);
99	      policy.remainingCap -= totalPayout;
100	      return { payout: totalPayout, remainingCap: policy.remainingCap };
101	    }
102	  });
103	  return { results };
