38	  premium: number;
39	}
40	
41	interface ClaimResult {
42	  payout: number;
43	  remainingCap: number;
44	}
45	
46	interface ScenarioResult {
47	  results: (QuoteResult | ClaimResult)[];
48	}
49	
50	const BASE_PREMIUMS: Record<string, number> = {
51	  sword: 100,
52	  amulet: 60,
53	  staff: 80,
54	  potion: 40,
55	  rune: 25,
56	  moonstone: 25,
57	};
58	
59	const INSURANCE_VALUES: Record<string, number> = {
60	  sword: 1000,
61	  amulet: 600,
62	  staff: 800,
63	  potion: 400,
64	  rune: 250,
65	  moonstone: 250,
66	};
67	
68	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
69	const DEDUCTIBLE = 100;
70	const PROCESSING_FEE = 5;
71	const BLOCK_SIZE = 3;
72	const BLOCK_PRICE = 60;
73	const CURSED_SURCHARGE_RATE = 0.5;
74	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
75	const HIGH_ENCHANTMENT_THRESHOLD = 5;
76	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
77	const LOYALTY_DISCOUNT_RATE = 0.2;
78	const LOYALTY_YEARS_THRESHOLD = 2;
79	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
80	
81	const calculateQuotePremium = (items: Item[], customer: { yearsWithMHPCO: number }, quoteIndex: number): number => {
82	  let basePremium = 0;
83	  let itemSurcharges = 0;
84	  const componentCounts: Record<string, number> = {};
85	
86	  for (const item of items) {
87	    if (COMPONENT_TYPES.has(item.type)) {
88	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
89	    } else {
90	      const itemBasePremium = BASE_PREMIUMS[item.type];
91	      basePremium += itemBasePremium;
92	      if (item.cursed) {
93	        itemSurcharges += itemBasePremium * CURSED_SURCHARGE_RATE;
94	      }
95	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
96	        itemSurcharges += itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
97	      }
98	    }
99	  }
100	
101	  for (const [type, count] of Object.entries(componentCounts)) {
102	    basePremium += count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUMS[type];
103	  }
104	
105	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
106	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
107	  const followUpDiscount = quoteIndex > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
108	  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
109	};
110	
111	const CAP_MULTIPLIER = 2;
112	
113	const calculateInsuranceSum = (items: Item[]): number =>
114	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
115	
116	const calculateClaimPayout = (step: ClaimStep, policy: Policy): ClaimResult => {
117	  let totalPayout = 0;
118	  for (const damage of step.incident.damages) {
119	    totalPayout += Math.max(0, damage.amount - DEDUCTIBLE);
120	  }
121	  totalPayout = Math.min(totalPayout, policy.remainingCap);
122	  policy.remainingCap -= totalPayout;
123	  return { payout: totalPayout, remainingCap: policy.remainingCap };
124	};
125	
126	export const processScenario = (scenario: Scenario): ScenarioResult => {
127	  let quoteCount = 0;
128	  const policies: Policy[] = [];
129	  const results = scenario.steps.map((step, index) => {
130	    if (step.op === "quote") {
131	      const premium = calculateQuotePremium(step.items, scenario.customer, quoteCount);
132	      const insuranceSum = calculateInsuranceSum(step.items);
133	      policies[index] = { items: step.items, insuranceSum, remainingCap: insuranceSum * CAP_MULTIPLIER };
134	      quoteCount++;
135	      return { premium };
136	    }
137	    return calculateClaimPayout(step, policies[step.policy]);
138	  });
139	  return { results };
140	};
